17→function resetDimensionTool(editorDispatch) {
18→  editorDispatch({
19→    type: 'UPDATE_TOOL_STATE',
20→    payload: {
21→      dimensionStartPoint: null,
22→      dimensionPreviewPoint: null,
23→      dimensionPreviewOffset: null,
24→    },
25→  });
26→}
